// Calculate comprehensive weekly performance metrics
const trades = $input.first().json.trades || [];
const account = $input.item(1).json;

if (trades.length === 0) {
  return {
    json: {
      hasTrades: false,
      totalTrades: 0,
      message: 'No trades closed this week. Weekly report skipped.'
    }
  };
}

// Basic stats
const totalTrades = trades.length;
const winningTrades = trades.filter(t => t.pnl_pips > 0);
const losingTrades = trades.filter(t => t.pnl_pips <= 0);
const winRate = (winningTrades.length / totalTrades * 100).toFixed(1);

const totalPips = trades.reduce((s, t) => s + (t.pnl_pips || 0), 0);
const totalPnl = trades.reduce((s, t) => s + (t.pnl_amount || 0), 0);

const avgWin = winningTrades.length > 0 
  ? winningTrades.reduce((s, t) => s + t.pnl_pips, 0) / winningTrades.length 
  : 0;
const avgLoss = losingTrades.length > 0 
  ? Math.abs(losingTrades.reduce((s, t) => s + t.pnl_pips, 0) / losingTrades.length) 
  : 0;
const profitFactor = avgLoss > 0 ? (avgWin / avgLoss).toFixed(2) : '∞';

const bestTrade = trades.reduce((best, t) => t.pnl_pips > (best?.pnl_pips || -Infinity) ? t : best, null);
const worstTrade = trades.reduce((worst, t) => t.pnl_pips < (worst?.pnl_pips || Infinity) ? t : worst, null);

const longestTrade = trades.reduce((longest, t) => (t.trade_age_minutes || 0) > (longest?.trade_age_minutes || 0) ? t : longest, null);
const shortestTrade = trades.reduce((shortest, t) => (t.trade_age_minutes || Infinity) < (shortest?.trade_age_minutes || Infinity) ? t : shortest, null);

// Strategy breakdown
const byStrategy = {};
trades.forEach(t => {
  const strat = t.label?.split('-')[0] || 'Unknown';
  if (!byStrategy[strat]) byStrategy[strat] = { wins: 0, losses: 0, pips: 0, trades: 0 };
  byStrategy[strat].trades++;
  byStrategy[strat].pips += t.pnl_pips || 0;
  if (t.pnl_pips > 0) byStrategy[strat].wins++;
  else byStrategy[strat].losses++;
});

// Session analysis
const bySession = {
  'Asian': { pips: 0, trades: 0, wins: 0 },
  'London': { pips: 0, trades: 0, wins: 0 },
  'NY': { pips: 0, trades: 0, wins: 0 },
  'Other': { pips: 0, trades: 0, wins: 0 }
};

// Symbol analysis
const bySymbol = {};
trades.forEach(t => {
  const sym = t.symbol;
  if (!bySymbol[sym]) bySymbol[sym] = { pips: 0, trades: 0, wins: 0 };
  bySymbol[sym].trades++;
  bySymbol[sym].pips += t.pnl_pips || 0;
  if (t.pnl_pips > 0) bySymbol[sym].wins++;
});

// Day of week analysis
const byDay = {
  'Monday': { pips: 0, trades: 0, wins: 0 },
  'Tuesday': { pips: 0, trades: 0, wins: 0 },
  'Wednesday': { pips: 0, trades: 0, wins: 0 },
  'Thursday': { pips: 0, trades: 0, wins: 0 },
  'Friday': { pips: 0, trades: 0, wins: 0 },
  'Saturday': { pips: 0, trades: 0, wins: 0 },
  'Sunday': { pips: 0, trades: 0, wins: 0 }
};

trades.forEach(t => {
  if (t.timestamp) {
    const day = new Date(t.timestamp).toLocaleDateString('en-US', { weekday: 'long' });
    if (byDay[day]) {
      byDay[day].trades++;
      byDay[day].pips += t.pnl_pips || 0;
      if (t.pnl_pips > 0) byDay[day].wins++;
    }
  }
});

// Calculate Sharpe-like metric (simplified)
const returns = trades.map(t => t.pnl_amount / 10000); // normalize to account size
const avgReturn = returns.reduce((s,r) => s+r, 0) / returns.length;
const variance = returns.reduce((s,r) => s + Math.pow(r - avgReturn, 2), 0) / returns.length;
const stdDev = Math.sqrt(variance);
const sharpeWeekly = stdDev > 0 ? (avgReturn / stdDev * Math.sqrt(52)).toFixed(2) : '∞';

// Account metrics
const weeklyReturn = account.balance > 0 ? ((account.equity - account.balance) / account.balance * 100).toFixed(2) : '0';
const monthlyReturn = account.equity > 10000 ? ((account.equity - 10000) / 10000 * 100).toFixed(2) : '0';

return {
  json: {
    hasTrades: true,
    // Period
    periodStart: trades.length > 0 ? trades[trades.length-1].timestamp : null,
    periodEnd: trades.length > 0 ? trades[0].timestamp : null,

    // Core metrics
    totalTrades,
    winningTrades: winningTrades.length,
    losingTrades: losingTrades.length,
    winRate,
    totalPips: totalPips.toFixed(1),
    totalPnl: totalPnl.toFixed(2),
    avgWin: avgWin.toFixed(1),
    avgLoss: avgLoss.toFixed(1),
    profitFactor,
    sharpeWeekly,

    // Extremes
    bestTrade: bestTrade ? { symbol: bestTrade.symbol, pips: bestTrade.pnl_pips, direction: bestTrade.direction } : null,
    worstTrade: worstTrade ? { symbol: worstTrade.symbol, pips: worstTrade.pnl_pips, direction: worstTrade.direction } : null,
    longestTrade: longestTrade ? { symbol: longestTrade.symbol, minutes: longestTrade.trade_age_minutes } : null,
    shortestTrade: shortestTrade ? { symbol: shortestTrade.symbol, minutes: shortestTrade.trade_age_minutes } : null,

    // Breakdowns
    byStrategy,
    bySession,
    bySymbol,
    byDay,

    // Account
    accountEquity: account.equity,
    accountBalance: account.balance,
    weeklyReturn,
    monthlyReturn,
    marginLevel: account.marginLevel,

    // Trade data
    trades: trades.slice(0, 10), // top 10 for detail

    generatedAt: new Date().toISOString()
  }
};

// Generate comprehensive weekly report
const metrics = $input.first().json;

if (!metrics.hasTrades) {
  return {
    json: {
      reportType: 'empty',
      message: metrics.message
    }
  };
}

// Best and worst strategy
const strategyEntries = Object.entries(metrics.byStrategy)
  .map(([name, data]) => ({ name, ...data, wr: (data.wins / data.trades * 100).toFixed(0) }))
  .sort((a, b) => b.pips - a.pips);

const bestStrategy = strategyEntries[0];
const worstStrategy = strategyEntries[strategyEntries.length - 1];

// Best and worst session
const sessionEntries = Object.entries(metrics.bySession)
  .map(([name, data]) => ({ name, ...data, wr: data.trades > 0 ? (data.wins / data.trades * 100).toFixed(0) : 0 }))
  .filter(s => s.trades > 0)
  .sort((a, b) => b.pips - a.pips);

const bestSession = sessionEntries[0];

// Best and worst day
const dayEntries = Object.entries(metrics.byDay)
  .map(([name, data]) => ({ name, ...data, wr: data.trades > 0 ? (data.wins / data.trades * 100).toFixed(0) : 0 }))
  .filter(d => d.trades > 0)
  .sort((a, b) => b.pips - a.pips);

const bestDay = dayEntries[0];
const worstDay = dayEntries[dayEntries.length - 1];

// Top symbol
const symbolEntries = Object.entries(metrics.bySymbol)
  .map(([name, data]) => ({ name, ...data, wr: (data.wins / data.trades * 100).toFixed(0) }))
  .sort((a, b) => b.pips - a.pips);

const topSymbol = symbolEntries[0];

// Generate recommendations
const recommendations = [];

if (metrics.winRate < 55) {
  recommendations.push('Consider reviewing entry criteria — win rate below 55%');
}
if (metrics.profitFactor < 1.5) {
  recommendations.push('Profit factor below 1.5 — improve R:R or entry timing');
}
if (worstStrategy && worstStrategy.pips < -20) {
  recommendations.push(`Reduce ${worstStrategy.name} strategy allocation — ${worstStrategy.pips.toFixed(0)} pips this week`);
}
if (bestSession && bestSession.name === 'Asian') {
  recommendations.push('Asian session performing well — consider increasing allocation');
}
if (bestDay && bestDay.name === 'Friday') {
  recommendations.push('Friday showing positive results — maintain current Friday exposure');
}
if (metrics.totalTrades < 10) {
  recommendations.push('Low trade count this week — ensure enough quality setups forming');
}
if (bestStrategy) {
  recommendations.push(`Focus on ${bestStrategy.name} setups — best performer this week`);
}

// Strategy table
const strategyTable = strategyEntries.map(s => 
  `| ${s.name} | ${s.trades} | ${s.pips >= 0 ? '+' : ''}${s.pips.toFixed(0)} | ${s.wr}% |`
).join('\n');

// Session table
const sessionTable = sessionEntries.map(s => 
  `| ${s.name} | ${s.trades} | ${s.pips >= 0 ? '+' : ''}${s.pips.toFixed(0)} | ${s.wr}% |`
).join('\n');

// Day table
const dayTable = dayEntries.map(d => 
  `| ${d.name} | ${d.trades} | ${d.pips >= 0 ? '+' : ''}${d.pips.toFixed(0)} | ${d.wr}% |`
).join('\n');

return {
  json: {
    reportType: 'full',

    // Summary
    summary: {
      totalTrades: metrics.totalTrades,
      winRate: metrics.winRate,
      totalPips: metrics.totalPips,
      totalPnl: metrics.totalPnl,
      profitFactor: metrics.profitFactor,
      sharpeWeekly: metrics.sharpeWeekly,
      weeklyReturn: metrics.weeklyReturn,
    },

    // Highlights
    bestTrade: metrics.bestTrade,
    worstTrade: metrics.worstTrade,
    longestTrade: metrics.longestTrade,

    // Rankings
    bestStrategy,
    worstStrategy,
    bestSession,
    bestDay,
    worstDay,
    topSymbol,

    // Tables
    strategyTable,
    sessionTable,
    dayTable,

    // Recommendations
    recommendations,

    // Account
    accountEquity: metrics.accountEquity,
    accountBalance: metrics.accountBalance,
    marginLevel: metrics.marginLevel,

    // Meta
    periodStart: metrics.periodStart,
    periodEnd: metrics.periodEnd,
    generatedAt: metrics.generatedAt,

    // Raw for Notion
    rawMetrics: metrics
  }
};

